function getErrorMessage(error){const util=require("node:util");if(typeof error!=="object"||error===null){return String(error);}
if(typeof error.messageTemplate==="string"){try{const template=require(`../messages/${error.messageTemplate}.js`);return template(error.messageData||{});}catch{}}
if(typeof error.stack==="string"){return error.stack;}
return util.format("%o",error);}
